package org.openmetadata.service.migration.context;

import java.util.HashMap;
import java.util.List;
import java.util.stream.Stream;
import lombok.Getter;
import lombok.extern.slf4j.Slf4j;
import org.jdbi.v3.core.Handle;

@Slf4j
public class MigrationContext {

  @Getter private final String version;
  @Getter private final List<MigrationOps> migrationOps;
  private final Handle handle;
  // Key is the Ops name and value the computed result
  @Getter private final HashMap<String, Long> results = new HashMap<>();

  public MigrationContext(String version, List<MigrationOps> migrationOps, Handle handle) {
    this.version = version;
    this.migrationOps =
        Stream.concat(migrationOps.stream(), CommonMigrationOps.getCommonOps().stream()).toList();
    this.handle = handle;
  }

  public void compute() {
    migrationOps.forEach(
        ops -> {
          ops.compute(handle);
          results.put(ops.getName(), ops.getResult());
        });
  }

  public void show() {
    LOG.debug("Version [{}] context is [{}]", version, results);
  }
}

package org.hswebframework.web.api.crud.entity;

import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.ObjectProvider;
import org.springframework.stereotype.Component;

import java.util.function.Supplier;

@Component
@Slf4j
public final class EntityFactoryHolder {

    static EntityFactory FACTORY;

    public static EntityFactory get() {
        if (FACTORY == null) {
            throw new IllegalStateException("EntityFactory Not Ready Yet");
        }
        return FACTORY;
    }


    public static <T> Class<T> getMappedType(Class<T> type) {
        if (FACTORY != null) {
            return FACTORY.getInstanceType(type);
        }
        return type;
    }

    public static <T> T newInstance(Class<T> type,
                                    Supplier<T> mapper) {
        if (FACTORY != null) {
            return FACTORY.newInstance(type,mapper);
        }
        return mapper.get();
    }

}

package org.zalando.nakadi.domain;

import com.google.common.base.Charsets;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.producer.ProducerRecord;

import java.util.EnumMap;
import java.util.Map;

public class KafkaHeaderTagSerde {

    public static void serialize(final Map<HeaderTag, String> consumerTags,
                                 final ProducerRecord<byte[], byte[]> record) {
        consumerTags.forEach((tag, value) ->
                record.headers().add(tag.name(), value.getBytes(Charsets.UTF_8)));
    }

    public static Map<HeaderTag, String> deserialize(final ConsumerRecord<byte[], byte[]> record) {
        final Map<HeaderTag, String> result = new EnumMap<>(HeaderTag.class);
        record.headers().forEach(header -> {
            HeaderTag.fromString(header.key()).ifPresent(tag ->
                    result.put(tag, new String(header.value(), Charsets.UTF_8))
            );
        });
        return result;
    }
}

package org.zalando.nakadi.util;

import com.google.common.hash.Hasher;
import com.google.common.hash.Hashing;
import org.springframework.stereotype.Component;
import org.zalando.nakadi.domain.SubscriptionBase;

import static com.google.common.base.Charsets.UTF_8;

@Component
public class HashGenerator {

    public String generateSubscriptionKeyFieldsHash(final SubscriptionBase subscription) {
        final Hasher hasher = Hashing.md5()
                .newHasher()
                .putString(subscription.getOwningApplication(), UTF_8)
                .putString(subscription.getConsumerGroup(), UTF_8);
        subscription.getEventTypes()
                .stream()
                .sorted()
                .forEach(et -> hasher.putString(et, UTF_8));
        return hasher.hash().toString();
    }

}

package org.zalando.nakadi.annotations.validation;

import javax.validation.Constraint;
import javax.validation.Payload;
import javax.validation.constraints.Pattern;
import javax.validation.constraints.Size;
import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

@Target({
        ElementType.FIELD, ElementType.METHOD, ElementType.PARAMETER, ElementType.ANNOTATION_TYPE,
        ElementType.TYPE_USE})
@Retention(RetentionPolicy.RUNTIME)
@Size(max = 63)
@Pattern(regexp = "^([a-zA-Z0-9]([a-zA-Z0-9_.-]*[a-zA-Z0-9])?)?$", message = "Should contain only allowed symbols")
@Constraint(validatedBy = {})
public @interface LabelValue {
    String message() default "{org.zalando.nakadi.annotations.validation.LabelValue.message}}";

    Class<?>[] groups() default {};

    Class<? extends Payload>[] payload() default {};
}

package org.hswebframework.web.context;

import java.util.HashMap;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;
import java.util.function.Supplier;

@SuppressWarnings("all")
class MapContext implements Context {

    private Map<String, Object> map = new ConcurrentHashMap<>();

    @Override
    public <T> Optional<T> get(ContextKey<T> key) {
        return Optional.ofNullable(map.get(key.getKey()))
                .map(v -> ((T) v));
    }

    @Override
    public <T> T getOrDefault(ContextKey<T> key, Supplier<? extends T> defaultValue) {
        return (T) map.computeIfAbsent(key.getKey(), __ -> defaultValue.get());
    }

    @Override
    public <T> void put(ContextKey<T> key, T value) {
        map.put(key.getKey(), value);
    }

    @Override
    public <T> T remove(ContextKey<T> key) {
        return (T)map.remove(key);
    }

    @Override
    public Map<String, Object> getAll() {
        return new HashMap<>(map);
    }

    @Override
    public void clean() {
        map.clear();
    }

}

package com.giffing.bucket4j.spring.boot.starter.core.predicates;

import com.giffing.bucket4j.spring.boot.starter.context.ExecutePredicate;
import lombok.extern.slf4j.Slf4j;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

@Slf4j
public abstract class MethodExecutePredicate<T> extends ExecutePredicate<T> {

    private List<String> methods = new ArrayList<>();

    public boolean testRequestMethod(String requestMethod) {
        var matches = methods
                .stream()
                .filter(m -> m.equalsIgnoreCase(requestMethod))
                .findFirst();
        log.debug("method-predicate;methods:{};value:{},result:{}", methods, requestMethod, matches.isPresent());
        return matches.isPresent();
    }

    @Override
    public String name() {
        return "METHOD";
    }

    @Override
    public ExecutePredicate<T> parseSimpleConfig(String simpleConfig) {
        this.methods = Arrays.stream(simpleConfig.split(","))
                .map(String::trim)
                .toList();
        return this;
    }

}

package springfox.documentation.builders;

import org.slf4j.Logger;
import org.slf4j.event.Level;

import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

import static org.slf4j.LoggerFactory.*;

public class NoopValidator<T> implements Validator<T> {
  private static final Logger LOGGER = getLogger("Validator");

  @Override
  public List<ValidationResult> validate(T builder) {
    return new ArrayList<>();
  }

  static List<ValidationResult> logProblems(List<ValidationResult> results) {
    List<ValidationResult> problems = results.stream()
        .filter(v -> v.getLevel().toInt() > Level.INFO.toInt())
        .collect(Collectors.toList());
    problems.forEach(v -> LOGGER.debug("{} [{}.{}] {}", v.getLevel(), v.getObject(), v.getField(), v.getMessage()));
    return problems;
  }
}

package com.alibaba.otter.canal.connector.core.util;

public class TimeZone {

    public final static String LOCATION_TIME_ZONE; // 当前时区

    static {
        java.util.TimeZone localTimeZone = java.util.TimeZone.getDefault();
        int rawOffset = localTimeZone.getRawOffset();
        String symbol = "+";
        if (rawOffset < 0) {
            symbol = "-";
        }
        rawOffset = Math.abs(rawOffset);
        int offsetHour = rawOffset / 3600000;
        int offsetMinute = rawOffset % 3600000 / 60000;
        String hour = String.format("%1$02d", offsetHour);
        String minute = String.format("%1$02d", offsetMinute);
        LOCATION_TIME_ZONE = symbol + hour + ":" + minute;
        java.util.TimeZone.setDefault(java.util.TimeZone.getTimeZone("GMT" + LOCATION_TIME_ZONE));
    }
}

package com.alibaba.otter.canal.filter;

import java.util.Map;

import org.apache.oro.text.regex.MalformedPatternException;
import org.apache.oro.text.regex.Pattern;
import org.apache.oro.text.regex.PatternCompiler;
import org.apache.oro.text.regex.Perl5Compiler;

import com.google.common.cache.CacheBuilder;
import com.google.common.collect.MigrateMap;

public class PatternUtils {

    private static Map<String, Pattern> patterns = MigrateMap.makeComputingMap(CacheBuilder.newBuilder().softValues(),
            pattern -> {
                try {
                    PatternCompiler pc = new Perl5Compiler();
                    return pc.compile(pattern,
                        Perl5Compiler.CASE_INSENSITIVE_MASK
                                | Perl5Compiler.READ_ONLY_MASK
                                | Perl5Compiler.SINGLELINE_MASK);
                } catch (MalformedPatternException e) {
                    throw new RuntimeException(e);
                }
            });

    public static Pattern getPattern(String pattern) {
        return patterns.get(pattern);
    }

    public static void clear() {
        patterns.clear();
    }
}

package org.jobrunr.storage.sql.common.db;

import java.util.ArrayList;
import java.util.List;

import static java.sql.Statement.SUCCESS_NO_INFO;
import static java.util.stream.Collectors.toList;
import static java.util.stream.IntStream.range;

public class SqlUtils {

    private SqlUtils() {
    }

    public static <T> List<T> getSucceededItems(List<T> items, int[] insertOrUpdateResult) {
        return range(0, insertOrUpdateResult.length)
                .filter(i -> hasBatchInsertOrUpdateSucceeded(insertOrUpdateResult[i]))
                .mapToObj(items::get)
                .collect(toList());
    }

    public static <T> List<T> getFailedItems(List<T> items, int[] insertOrUpdateResult) {
        List<T> succeededItems = getSucceededItems(items, insertOrUpdateResult);
        List<T> result = new ArrayList<>(items);
        result.removeAll(succeededItems);
        return result;
    }

    private static boolean hasBatchInsertOrUpdateSucceeded(int insertOrUpdateResult) {
        return insertOrUpdateResult == SUCCESS_NO_INFO || insertOrUpdateResult > 0;
    }
}

package org.zalando.nakadi.util;

import com.google.common.collect.ImmutableSet;

import java.util.Set;

public class NakadiCollectionUtils {
    public static class Diff<T> {
        private final ImmutableSet<T> added;
        private final ImmutableSet<T> removed;

        Diff(final ImmutableSet<T> added, final ImmutableSet<T> removed) {
            this.added = added;
            this.removed = removed;
        }

        public ImmutableSet<T> getAdded() {
            return added;
        }

        public ImmutableSet<T> getRemoved() {
            return removed;
        }
    }

    public static <T> Diff<T> difference(final Set<T> oldSet, final Set<T> newSet) {
        final ImmutableSet.Builder<T> addedBuilder = ImmutableSet.builder();
        newSet.stream()
                .filter(v -> !oldSet.contains(v))
                .forEach(addedBuilder::add);
        final ImmutableSet.Builder<T> removedBuilder = ImmutableSet.builder();
        oldSet.stream()
                .filter(v -> !newSet.contains(v))
                .forEach(removedBuilder::add);
        return new Diff<>(addedBuilder.build(), removedBuilder.build());
    }
}

